package com.flowledger.organization.controller;
import com.flowledger.common.dto.ApiResponse;import com.flowledger.common.security.SecurityUtils;import com.flowledger.organization.dto.*;import com.flowledger.organization.service.OrganizationService;import jakarta.validation.Valid;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;
@RestController @RequestMapping("/api/v1/organizations") public class OrganizationController {private final OrganizationService service;public OrganizationController(OrganizationService s){service=s;}@GetMapping("/current") ApiResponse<OrganizationResponse> current(){return ApiResponse.of(service.current());}@PutMapping("/current") ApiResponse<OrganizationResponse> update(@Valid @RequestBody UpdateOrganizationRequest r){return ApiResponse.of(service.update(SecurityUtils.currentOrganizationId(),r));}@PostMapping("/current/logo") ApiResponse<String> logo(@RequestParam MultipartFile file){return ApiResponse.of(service.uploadLogo(SecurityUtils.currentOrganizationId(),file));}}
